parameters.jsCode:
const base = $('Normalize Input').first().json;
const classifierRaw = $('Intake Classifier Agent').first().json;
const sentimentRaw = $('Sentiment Analyzer Agent').first().json;

let classifier = {};
let sentiment = {};

try {
  classifier = JSON.parse(classifierRaw.choices?.[0]?.message?.content || '{}');
} catch (error) {
  classifier = { category: 'general', urgency: 'medium', reason: 'classifier_parse_failed' };
}

try {
  sentiment = JSON.parse(sentimentRaw.choices?.[0]?.message?.content || '{}');
} catch (error) {
  sentiment = { sentiment: 'neutral', reason: 'sentiment_parse_failed' };
}

return [{
  json: {
    ...base,
    category: classifier.category || 'general',
    urgency: classifier.urgency || 'medium',
    classifier_reason: classifier.reason || '',
    sentiment: sentiment.sentiment || 'neutral',
    sentiment_reason: sentiment.reason || ''
  }
}];

const item = $input.first().json;
const query = (item.customer_query || '').toLowerCase();

const faqs = [
  { id: 'FAQ-001', question: 'reset password forgot password', answer: 'Click on "Forgot Password" on the login page and follow the instructions.', category: 'account' },
  { id: 'FAQ-002', question: 'change email update email', answer: 'Go to account settings and update your email in the profile section.', category: 'account' },
  { id: 'FAQ-003', question: 'delete account remove account', answer: 'Please contact support or go to settings and select "Delete Account".', category: 'account' },
  { id: 'FAQ-004', question: 'update profile profile information', answer: 'Navigate to your account settings and edit your profile details.', category: 'account' },
  { id: 'FAQ-005', question: 'multiple accounts more than one account', answer: 'No, only one account per user is allowed.', category: 'account' },
  { id: 'FAQ-006', question: 'enable two factor authentication 2fa', answer: 'Go to security settings and enable 2FA for additional protection.', category: 'account' },
  { id: 'FAQ-007', question: 'unable to log in cannot login login issue', answer: 'Check your credentials and ensure your account is active. Try resetting your password if needed.', category: 'account' },
  { id: 'FAQ-008', question: 'update billing information payment method', answer: 'Go to account settings and open the billing section to update your payment method.', category: 'billing' },
  { id: 'FAQ-009', question: 'charged twice duplicate charge double charge', answer: 'Please contact support with your transaction details for a refund investigation.', category: 'billing' },
  { id: 'FAQ-010', question: 'cancel subscription cancel my plan', answer: 'Go to subscription settings and click "Cancel Subscription".', category: 'billing' },
  { id: 'FAQ-011', question: 'refund after cancellation refund policy', answer: 'Refunds depend on our policy. Please check the refund terms or contact support.', category: 'billing' },
  { id: 'FAQ-012', question: 'payment failed payment issue money deducted', answer: 'Ensure your payment details are correct and that you have sufficient balance.', category: 'billing' },
  { id: 'FAQ-013', question: 'change subscription plan upgrade downgrade', answer: 'Yes, you can upgrade or downgrade your plan from the billing section.', category: 'billing' },
  { id: 'FAQ-014', question: 'student discounts student discount', answer: 'Yes, we offer discounts for students with valid verification.', category: 'billing' },
  { id: 'FAQ-015', question: 'view invoices invoices bill receipt', answer: 'Go to the billing section in your account to download your invoices.', category: 'billing' },
  { id: 'FAQ-016', question: 'app not loading website not loading page not loading', answer: 'Try refreshing the page, clearing cache, or checking your internet connection.', category: 'technical' },
  { id: 'FAQ-017', question: 'app crashing app crash website crashing', answer: 'Restart the app and ensure you are using the latest version.', category: 'technical' },
  { id: 'FAQ-018', question: 'error message error code', answer: 'Please note the error message and try again. Contact support if it persists.', category: 'technical' },
  { id: 'FAQ-019', question: 'website is slow app is slow slow loading', answer: 'Check your internet connection and try accessing during non-peak hours.', category: 'technical' },
  { id: 'FAQ-020', question: 'update app latest version', answer: 'Visit the app store or website and download the latest version.', category: 'technical' },
  { id: 'FAQ-021', question: 'features not working broken feature', answer: 'Try restarting the app or clearing cache. Contact support if the issue continues.', category: 'technical' },
  { id: 'FAQ-022', question: 'cannot upload files upload issue file upload', answer: 'Check file size limits and supported formats before uploading.', category: 'technical' },
  { id: 'FAQ-023', question: 'service down outage status', answer: 'Check our status page or wait a few minutes and try again.', category: 'technical' },
  { id: 'FAQ-024', question: 'what services do you offer services', answer: 'We provide various digital services including account management and support tools.', category: 'general' },
  { id: 'FAQ-025', question: 'contact support reach support', answer: 'You can reach support via email, chat, or help center.', category: 'general' },
  { id: 'FAQ-026', question: 'working hours support hours', answer: 'Our support team is available 24/7.', category: 'general' },
  { id: 'FAQ-027', question: 'help documentation help center guides', answer: 'Visit our help center for detailed guides and tutorials.', category: 'general' },
  { id: 'FAQ-028', question: 'mobile app android ios app', answer: 'Yes, our app is available on both Android and iOS platforms.', category: 'general' },
  { id: 'FAQ-029', question: 'give feedback submit feedback', answer: 'You can submit feedback through the app or contact support.', category: 'general' },
  { id: 'FAQ-030', question: 'data secure privacy security', answer: 'Yes, we follow strict security protocols to protect your data.', category: 'general' },
  { id: 'FAQ-031', question: 'internationally global worldwide', answer: 'Yes, our services are available globally.', category: 'general' }
];

function scoreFAQ(currentQuery, faqQuestion) {
  const queryWords = currentQuery.split(/[^a-z0-9]+/).filter(Boolean);
  const faqWords = faqQuestion.split(/[^a-z0-9]+/).filter(Boolean);
  let score = 0;
  for (const word of queryWords) {
    if (faqWords.includes(word)) score += 1;
  }
  return score;
}

let best = null;
let bestScore = 0;
for (const faq of faqs) {
  const score = scoreFAQ(query, faq.question);
  if (score > bestScore) {
    best = faq;
    bestScore = score;
  }
}

const matched_faq = Boolean(best && bestScore >= 2);
const faq_answer = matched_faq ? best.answer : '';
const faq_id = matched_faq ? best.id : '';
const faq_confidence = matched_faq ? (bestScore >= 3 ? 'high' : 'medium') : 'low';

return [{
  json: {
    ...item,
    matched_faq,
    faq_answer,
    faq_id,
    faq_confidence
  }
}];

const item = $input.first().json;
const query = (item.customer_query || '').toLowerCase();
const negativeSignals = ['angry', 'frustrated', 'refund', 'complaint', 'charged twice', 'urgent', 'not working', 'terrible', 'bad service', 'cancel immediately', 'money deducted'];
const hasNegativeSignal = negativeSignals.some((word) => query.includes(word));

const escalate = (
  item.matched_faq === false ||
  item.urgency === 'high' ||
  item.sentiment === 'negative' ||
  hasNegativeSignal
);

let summary = `Customer query: ${item.customer_query}. Category: ${item.category}. Urgency: ${item.urgency}. Sentiment: ${item.sentiment}.`;
if (!item.matched_faq) summary += ' No FAQ match found.';

return [{
  json: {
    ...item,
    escalate,
    escalation_reason: escalate
      ? 'Complex, urgent, negative, or unmatched query requiring human review'
      : 'FAQ matched and safe to auto-resolve',
    summary_for_human: summary
  }
}];

const item = $input.first().json;
const ticketId = 'TICK-' + Date.now();
return [{
  json: {
    ...item,
    final_status: 'escalated_to_human',
    escalated: true,
    ticket_id: ticketId,
    response_text: `Your request has been escalated to a human support agent. Ticket ID: ${ticketId}. Our team will review it shortly.`
  }
}];
